/*
 * AI Evaluation Platform Docs Framework
 * Matches a modern, minimalist SaaS-style documentation UI
 */

/* =============================
   Design tokens
   ============================= */

:root {
  /* Color palette */
  --color-primary-500: #7c3aed;
  --color-primary-700: #4c1d95;

  --color-secondary-50: #ede9fe;
  --color-secondary-600: #1d4ed8;

  --color-accent-900: #1e0b3a;

  --color-neutral-0: #ffffff;
  --color-neutral-50: #f9fafb;
  --color-neutral-100: #f3f4f6;
  --color-neutral-200: #e5e7eb;
  --color-neutral-500: #6b7280;
  --color-neutral-900: #111827;

  --color-success: #16a34a;
  --color-error: #dc2626;
  --color-warning: #f97316;
  --color-info: #2563eb;

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;
  --font-code: "JetBrains Mono", monospace;

  --font-size-h1: 2rem;        /* 32px */
  --font-size-h2: 1.5rem;      /* 24px */
  --font-size-h3: 1.25rem;     /* 20px */
  --font-size-body: 1rem;      /* 16px */
  --font-size-small: 0.8125rem;/* 13px */

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* Spacing scale (4px base subdivisions of 8px units) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 12px;
  --space-4: 16px;
  --space-5: 24px;
  --space-6: 32px;
  --space-7: 48px;
  --space-8: 64px;

  /* Layout */
  --header-height: 80px; /* approximate combined header rows */
  --content-max-width: 1200px;
  --sidebar-width: 260px;
  --border-radius-pill: 999px;
  --border-radius-md: 12px;
  --border-radius-sm: 6px;

  --shadow-soft: 0 10px 25px rgba(15, 23, 42, 0.06);
}

/* =============================
   Global reset & base
   ============================= */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-relaxed);
  color: var(--color-neutral-900);
  background-color: var(--color-neutral-0);
  -webkit-font-smoothing: antialiased;
}

img,
video {
  max-width: 100%;
  height: auto;
}

a {
  color: var(--color-secondary-600);
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

code,
pre {
  font-family: var(--font-code);
}

main:focus {
  outline: none;
}

/* =============================
   Header
   ============================= */

.site-header {
  position: sticky;
  top: 0;
  z-index: 20;
  background-color: var(--color-neutral-0);
  border-bottom: 1px solid var(--color-neutral-200);
  backdrop-filter: blur(10px);
}

.header-inner {
  max-width: var(--content-max-width);
  margin: 0 auto;
  padding: var(--space-2) var(--space-5) 0 var(--space-5);
  display: flex;
  flex-direction: column;
  gap: var(--space-1);
}

.header-row {
  display: flex;
  align-items: center;
}

.header-row--top {
  gap: var(--space-3);
}

/* Logo */

.logo {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 1rem;
  color: var(--color-neutral-900);
  text-decoration: none;
}

.logo-mark {
  width: 24px;
  height: 24px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, #f9fafb, var(--color-accent-900));
  box-shadow: 0 0 0 1px rgba(15, 23, 42, 0.06);
}

.logo-text {
  letter-spacing: 0.01em;
}

/* Search */

.header-search {
  flex: 1 1 auto;
  max-width: 480px;
  margin-inline: auto;
  display: flex;
  align-items: center;
  gap: var(--space-2);
  padding: 0 var(--space-3);
  height: 44px;
  border-radius: var(--border-radius-pill);
  border: 1px solid var(--color-neutral-200);
  background-color: var(--color-neutral-0);
  box-shadow: 0 1px 2px rgba(15, 23, 42, 0.03);
}

.header-search:focus-within {
  border-color: var(--color-primary-500);
  box-shadow: 0 0 0 1px rgba(124, 58, 237, 0.4);
}

.header-search-icon {
  font-size: 0.9rem;
  color: var(--color-neutral-500);
}

.header-search input[type="search"] {
  flex: 1 1 auto;
  border: none;
  outline: none;
  font: inherit;
  color: var(--color-neutral-900);
}

.header-search input::placeholder {
  color: var(--color-neutral-500);
}

.header-search-kbd {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 2px 8px;
  border-radius: 999px;
  border: 1px solid var(--color-neutral-200);
  background-color: var(--color-neutral-0);
  color: var(--color-neutral-500);
  font-size: 0.75rem;
}

/* Primary CTA – styled like "HomePage" pill in the design */

.header-cta {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 10px 18px;
  border-radius: var(--border-radius-pill);
  background-color: var(--color-accent-900);
  color: var(--color-neutral-0);
  font-family: var(--font-heading);
  font-size: 0.9rem;
  font-weight: var(--font-weight-semibold);
  text-decoration: none;
  box-shadow: var(--shadow-soft);
}

.header-cta:hover {
  text-decoration: none;
  background-color: var(--color-primary-700);
}

.header-cta-arrow {
  font-size: 1rem;
}

/* Top navigation (row below search) */

.primary-nav {
  margin-top: var(--space-1);
}

.primary-nav ul {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-4);
  list-style: none;
  margin: 0;
  padding: 0 0 var(--space-2) 0;
}

.primary-nav a {
  position: relative;
  font-size: 0.95rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-neutral-500);
  padding-bottom: 10px;
  text-decoration: none;
}

.primary-nav a::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 2px;
  border-radius: 999px;
  background-color: transparent;
}

.primary-nav a:hover {
  color: var(--color-neutral-900);
}

.primary-nav a:hover::after {
  background-color: var(--color-neutral-200);
}

.primary-nav a[aria-current="page"],
.primary-nav a.is-active {
  color: var(--color-neutral-900);
}

.primary-nav a[aria-current="page"]::after,
.primary-nav a.is-active::after {
  background-color: var(--color-primary-500);
}

/* =============================
   Layout shell
   ============================= */

.shell {
  max-width: var(--content-max-width);
  margin: 0 auto;
  padding: var(--space-5) var(--space-5) var(--space-7) var(--space-5);
  display: grid;
  grid-template-columns: minmax(0, var(--sidebar-width)) minmax(0, 1fr);
  gap: var(--space-5);
}

@media (max-width: 960px) {
  .shell {
    grid-template-columns: minmax(0, 1fr);
  }

  .sidebar {
    display: none;
  }
}

/* =============================
   Sidebar navigation (left)
   ============================= */

.sidebar {
  position: relative;
}

.sidebar-inner {
  position: sticky;
  top: calc(var(--header-height) + var(--space-3));
  max-height: calc(100vh - var(--header-height) - var(--space-5));
  overflow-y: auto;
  padding: var(--space-4);
  border-radius: 18px;
  background-color: var(--color-neutral-100);
}

.sidebar-group + .sidebar-group {
  margin-top: var(--space-5);
}

.sidebar-heading {
  margin: 0 0 var(--space-2) 0;
  font-family: var(--font-heading);
  font-size: 0.75rem;
  font-weight: var(--font-weight-semibold);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--color-neutral-500);
}

.sidebar-nav {
  list-style: none;
  margin: 0;
  padding: 0;
}

.sidebar-nav li + li {
  margin-top: 6px;
}

.sidebar-nav a {
  display: block;
  padding: 6px 10px;
  border-radius: 999px;
  font-size: 0.9rem;
  color: var(--color-neutral-700, var(--color-neutral-900));
  text-decoration: none;
}

.sidebar-nav a:hover {
  background-color: var(--color-neutral-0);
}

.sidebar-nav a.is-active,
.sidebar-nav a[aria-current="page"] {
  background-color: var(--color-secondary-50);
  color: var(--color-primary-500);
  font-weight: var(--font-weight-medium);
}

/* =============================
   Main content area
   ============================= */

.main-content {
  min-height: 60vh;
}

.main-content > :first-child {
  margin-top: 0;
}

/* Headings */

.main-content h1,
.main-content h2,
.main-content h3,
.main-content h4 {
  font-family: var(--font-heading);
  line-height: var(--line-height-tight);
  margin-top: var(--space-5);
  margin-bottom: var(--space-2);
}

.main-content h1 {
  font-size: var(--font-size-h1);
  font-weight: var(--font-weight-bold);
}

.main-content h2 {
  font-size: var(--font-size-h2);
  font-weight: var(--font-weight-semibold);
}

.main-content h3 {
  font-size: var(--font-size-h3);
  font-weight: var(--font-weight-semibold);
}

.main-content p {
  margin-top: 0;
  margin-bottom: var(--space-3);
}

/* Links inside content */

.main-content a {
  color: var(--color-primary-500);
}

.main-content a:hover {
  color: var(--color-primary-700);
}

/* =============================
   Footer
   ============================= */

.site-footer {
  border-top: 1px solid var(--color-neutral-200);
  background-color: var(--color-neutral-0);
}

.footer-inner {
  max-width: var(--content-max-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-5) var(--space-5) var(--space-5);
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-3);
}

.footer-meta {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  color: var(--color-neutral-500);
  font-size: 0.9rem;
}

.footer-logo-mark {
  width: 16px;
  height: 16px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, #f9fafb, var(--color-primary-500));
}

.footer-logo-text {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-medium);
  color: var(--color-neutral-900);
}

.footer-copy {
  margin-left: var(--space-2);
}

.footer-nav ul {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
  margin: 0;
  padding: 0;
  list-style: none;
}

.footer-nav a {
  font-size: 0.9rem;
  color: var(--color-neutral-500);
  text-decoration: none;
}

.footer-nav a:hover {
  color: var(--color-neutral-900);
  text-decoration: underline;
}

@media (max-width: 640px) {
  .footer-inner {
    flex-direction: column;
    align-items: flex-start;
  }
}

/* =============================
   Utility classes
   ============================= */

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  border: 0;
}
